import{_ as a,o,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Browser Timings","description":"","frontmatter":{},"headers":[],"relativePath":"pt/configuration/browser-timings.md","filePath":"pt/configuration/browser-timings.md"}'),t={name:"pt/configuration/browser-timings.md"};function n(s,e,d,m,c,l){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="browser-timings" tabindex="-1"><i class="ph ph-clock-countdown"></i> Browser Timings <a class="header-anchor" href="#browser-timings" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-clock-countdown&quot;&gt;&lt;/i&gt; Browser Timings&quot;">​</a></h1><p>Esta página detalha as restrições técnicas da arquitetura WebGL que dizem respeito ao parâmetro <code>Application.targetFrameRate</code>.</p><p>Quando um projeto Unity é compilado para WebGL, o parâmetro <code>Application.targetFrameRate</code> não altera apenas o limite interno de frames da engine, mas também modifica a <strong>API de base do navegador</strong> através da qual o loop principal corre.</p><h2 id="uncapped-sem-limite-requestanimationframe" tabindex="-1">Uncapped (Sem Limite) (requestAnimationFrame) <a class="header-anchor" href="#uncapped-sem-limite-requestanimationframe" aria-label="Permalink to &quot;Uncapped (Sem Limite) (requestAnimationFrame)&quot;">​</a></h2><p>Se você remover o limite da taxa de frames (dependendo da versão do Unity, configurando <code>Application.targetFrameRate</code> para <code>-1</code> ou <code>0</code>), o compilador Emscripten ligará o loop principal do Unity diretamente à API do navegador <code>window.requestAnimationFrame</code>.</p><ul><li><strong>Vantagens:</strong> É o método de renderização mais nativo, suave e preciso na web. O navegador irá sincronizar automaticamente a chamada com a taxa de atualização do monitor do jogador (VSync).</li><li><strong>Análise:</strong> As métricas <code>cpuMainThreadFrameTime</code> (lidas pelo WebAP) irão refletir o tempo <strong>real</strong> que a CPU gastou calculando física e scripts.</li></ul><h2 id="artificialmente-limitado-settimeout" tabindex="-1">Artificialmente Limitado (setTimeout) <a class="header-anchor" href="#artificialmente-limitado-settimeout" aria-label="Permalink to &quot;Artificialmente Limitado (setTimeout)&quot;">​</a></h2><p>Se você forçar estritamente uma taxa de frames (por exemplo, <code>Application.targetFrameRate = 30</code>), o Emscripten será obrigado a abandonar o <code>requestAnimationFrame</code>. Em vez disso, utilizará a API <code>setTimeout()</code> ou combinações complexas de temporizadores internos para atrasar o loop artificialmente.</p><div class="warning custom-block"><p class="custom-block-title">Distorção de Métricas de CPU (A Armadilha do Emscripten)</p><p>Temporizadores artificiais introduzem uma discrepância enorme ao medir o tempo da CPU. O processador pode concluir todos os cálculos da lógica do jogo num tempo super-rápido de 5 ms e entrar em inatividade, mas a corrotina <code>WaitForEndOfFrame</code> não continuará até que o temporizador do <code>setTimeout</code> acabe.</p><p><strong>Como resultado:</strong> O <code>FrameTimingManager</code> gravará este tempo de espera dentro dos timings da CPU. O profiler (e o Tracker do WebAP) irão deduzir que tem um <em>Gargalo de CPU (CPU Bottleneck)</em>, mesmo que o processador esteja funcionalmente inativo e os frames estejam simplesmente à espera do temporizador do navegador.</p></div><h2 id="a-estrategia-correta-de-configuracao" tabindex="-1">A Estratégia Correta de Configuração <a class="header-anchor" href="#a-estrategia-correta-de-configuracao" aria-label="Permalink to &quot;A Estratégia Correta de Configuração&quot;">​</a></h2><p>Para o Web Adaptive Performance funcionar da melhor forma no navegador:</p><ol><li><strong>Não use <code>Application.targetFrameRate</code></strong>. Deixe em <code>-1</code> (sem limites).</li><li>Especifique o seu FPS desejado nas configurações do plugin (<code>Target Min FPS = 60</code>). O WebAP irá utilizar esse valor não como um limite rígido, mas como a base para tomar decisões sobre a qualidade de renderização.</li></ol>',12)])])}const g=a(t,[["render",n]]);export{u as __pageData,g as default};
